package com.securestack.model;import jakarta.persistence.*;import java.time.Instant;import java.util.*;import com.securestack.model.Enums.*;
public class Entities{
@Entity public static class Scan{ @Id public UUID id=UUID.randomUUID(); public String name; public Instant createdAt=Instant.now(); @Enumerated(EnumType.STRING) public ScanStatus status=ScanStatus.COMPLETED; public int riskScore; @Enumerated(EnumType.STRING) public RiskLevel riskLevel; public int fileCount; public int findingCount; @Column(length=5000) public String executiveSummary; @Column(length=5000) public String remediationSummary; @ElementCollection public List<String> files=new ArrayList<>(); }
@Entity public static class Finding{ @Id public UUID id=UUID.randomUUID(); public UUID scanId; public String fileName; public Integer lineNumber; public String title; @Column(length=4000) public String description; @Enumerated(EnumType.STRING) public Severity severity; @Enumerated(EnumType.STRING) public Category category; @Enumerated(EnumType.STRING) public Confidence confidence; @Column(length=1000) public String evidence; @Column(length=2000) public String recommendation; @Column(length=1000) public String secureExample; @Enumerated(EnumType.STRING) public FindingStatus status=FindingStatus.OPEN; public String ruleId; }
}
